'use client';

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plus, Search, Menu, LogOut, Folder,
  Star, FileText, Play, ChevronLeft, X,
  Trash2, Info, RotateCcw, Briefcase, Home, Camera, LayoutGrid
} from 'lucide-react';
import {
  DndContext, 
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
} from '@dnd-kit/core';
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  horizontalListSortingStrategy,
} from '@dnd-kit/sortable';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import styles from './page.module.css';

// --- רכיב פריט נגרר ---
function SortableItem(props) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: props.id });
  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    zIndex: isDragging ? 10 : 1,
    opacity: isDragging ? 0.5 : 1,
    ...props.style
  };

  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners} onClick={props.onClick} onContextMenu={props.onContextMenu} className={props.className}>
      {props.children}
    </div>
  );
}

export default function ClientDashboard({ user = { name: 'משתמש' }, onLogout }) {
  // --- סטייטים ---
  const [isMounted, setIsMounted] = useState(false);
  const [spaces, setSpaces] = useState([]);
  const [activeSpace, setActiveSpace] = useState(null);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [activeCategoryTab, setActiveCategoryTab] = useState('ראשי');
  const [activeCustomTab, setActiveCustomTab] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  
  // מודלים (Modals)
  const [isAddSpaceModalOpen, setAddSpaceModalOpen] = useState(false);
  const [isAddTabModalOpen, setAddTabModalOpen] = useState(false);
  const [isRecycleBinOpen, setIsRecycleBinOpen] = useState(false);
  const [showInfoTooltip, setShowInfoTooltip] = useState(false);

  const tabsScrollRef = useRef(null);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  // --- טעינת נתונים אמיתית מהשרת (החלק שתוקן!) ---
  useEffect(() => {
    setIsMounted(true);
    if (window.innerWidth <= 768) setSidebarOpen(false);
    fetchSpaces();
  }, []);

  const fetchSpaces = async () => {
    try {
      const res = await fetch('/api/spaces');
      const data = await res.json();
      setSpaces(data);
      if (data.length > 0 && !activeSpace) {
        setActiveSpace(data[0]);
        if (data[0].customTabs?.length > 0) {
          setActiveCustomTab(data[0].customTabs[0]);
        }
      }
    } catch (err) {
      console.error("Error fetching spaces:", err);
    }
  };

  // --- פונקציות עזר ---
  const scrollTabsLeft = () => {
    if (tabsScrollRef.current) {
      tabsScrollRef.current.scrollBy({ left: -150, behavior: 'smooth' });
    }
  };

  const handleDragEndTabs = (event) => {
    const { active, over } = event;
    if (active.id !== over.id) {
      const oldIndex = activeSpace.customTabs.indexOf(active.id);
      const newIndex = activeSpace.customTabs.indexOf(over.id);
      const newTabs = arrayMove(activeSpace.customTabs, oldIndex, newIndex);
      
      const updatedSpace = { ...activeSpace, customTabs: newTabs };
      setActiveSpace(updatedSpace);
      setSpaces(spaces.map(s => s._id === updatedSpace._id ? updatedSpace : s));
    }
  };

  const renderSpaceIcon = (iconName, color, size = 18) => {
    const props = { size, style: { color: color || '#94a3b8' } };
    switch (iconName) {
      case 'Briefcase': return <Briefcase {...props} />;
      case 'Home': return <Home {...props} />;
      case 'Camera': return <Camera {...props} />;
      case 'Star': return <Star {...props} />;
      default: return <Folder {...props} />;
    }
  };

  // --- לוגיקת סל מחזור (Soft Delete) ---
  const softDeleteVideo = (videoId) => {
    const updatedSpaces = spaces.map(space => {
      if (space._id === activeSpace._id) {
        return { ...space, videos: space.videos.map(v => v._id === videoId ? { ...v, isDeleted: true } : v) };
      }
      return space;
    });
    setSpaces(updatedSpaces);
    setActiveSpace(updatedSpaces.find(s => s._id === activeSpace._id));
  };

  const restoreItem = (itemId, type) => {
    const updatedSpaces = spaces.map(space => {
      if (type === 'video') {
        return { ...space, videos: space.videos.map(v => v._id === itemId ? { ...v, isDeleted: false } : v) };
      }
      return space;
    });
    setSpaces(updatedSpaces);
    setActiveSpace(updatedSpaces.find(s => s._id === activeSpace._id));
  };

  if (!isMounted) return null;

  // --- סינונים לתצוגה ---
  const currentSpaceTabs = activeSpace?.customTabs || [];
  const activeFavorites = (activeSpace?.favorites || []).filter(f => !f.isDeleted);
  const activeDocs = (activeSpace?.documents || []).filter(d => !d.isDeleted);
  const activeVideos = (activeSpace?.videos || []).filter(v => !v.isDeleted);
  const deletedVideos = spaces.flatMap(s => s.videos || []).filter(v => v.isDeleted);

  return (
    <div className={styles.dashboardContainer} dir="rtl">
      
      {/* --- תפריט צד --- */}
      <aside className={`${styles.sidebar} ${isSidebarOpen ? styles.open : styles.closed}`}>
        <div className={styles.sidebarHeader} style={{ justifyContent: isSidebarOpen ? 'flex-start' : 'center', padding: isSidebarOpen ? '20px' : '20px 0' }}>
          <button onClick={() => setSidebarOpen(!isSidebarOpen)} className={styles.hamburger}><Menu size={24} /></button>
          {isSidebarOpen && <h2 className={styles.brandTitle} style={{ marginRight: '10px' }}>מרכז השליטה</h2>}
        </div>
        
        <nav className={styles.spacesNav} style={{ flex: 1, overflowY: 'auto', overflowX: 'hidden' }}>
           <button onClick={() => setAddSpaceModalOpen(true)} className={styles.addSpaceBtn} style={{ justifyContent: isSidebarOpen ? 'flex-start' : 'center', padding: isSidebarOpen ? '10px' : '10px 0', width: isSidebarOpen ? 'calc(100% - 40px)' : '40px', margin: '0 auto 15px auto', display: 'flex', alignItems: 'center' }} title={!isSidebarOpen ? "הוספת מרחב" : ""}>
             <Plus size={18} /> {isSidebarOpen && <span style={{ marginRight: '8px' }}>הוספת מרחב</span>}
           </button>
           
           <div className={styles.spacesList}>
             {spaces.map(space => (
               <div 
                 key={space._id} 
                 className={`${styles.spaceItem} ${activeSpace?._id === space._id ? styles.activeSpace : ''}`} 
                 onClick={() => { setActiveSpace(space); setActiveCategoryTab('ראשי'); setActiveCustomTab(space.customTabs?.[0] || null); if (window.innerWidth <= 768) setSidebarOpen(false); }} 
                 style={{ justifyContent: isSidebarOpen ? 'flex-start' : 'center', padding: isSidebarOpen ? '10px' : '12px 0', width: isSidebarOpen ? 'calc(100% - 40px)' : '40px', margin: '0 auto 5px auto', borderRadius: '8px', display: 'flex', alignItems: 'center' }}
                 title={!isSidebarOpen ? space.name : ""}
               >
                 <span className={styles.spaceIcon} style={{ margin: isSidebarOpen ? '0' : '0 auto', display: 'flex' }}>
                   {renderSpaceIcon(space.iconName, space.color)}
                 </span> 
                 {isSidebarOpen && <span className={styles.spaceName} style={{ marginRight: '10px', whiteSpace: 'nowrap' }}>{space.name}</span>}
               </div>
             ))}
           </div>
        </nav>
        
        {/* תחתית התפריט */}
        <div className={styles.sidebarFooter} style={{ padding: isSidebarOpen ? '20px 20px 40px 20px' : '20px 0 40px 0', borderTop: '1px solid #334155', display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <div onClick={() => setIsRecycleBinOpen(true)} style={{ display: 'flex', alignItems: 'center', justifyContent: isSidebarOpen ? 'flex-start' : 'center', width: isSidebarOpen ? 'calc(100% - 20px)' : '100%', margin: '0 auto', cursor: 'pointer', color: '#94a3b8', transition: 'color 0.2s' }} title={!isSidebarOpen ? "סל מחזור" : ""} onMouseEnter={(e) => e.currentTarget.style.color = '#38bdf8'} onMouseLeave={(e) => e.currentTarget.style.color = '#94a3b8'}>
            <Trash2 size={18} /> 
            {isSidebarOpen && <span style={{ marginRight: '10px', whiteSpace: 'nowrap' }}>סל מחזור</span>}
          </div>
          <div onClick={onLogout} style={{ display: 'flex', alignItems: 'center', justifyContent: isSidebarOpen ? 'flex-start' : 'center', width: isSidebarOpen ? 'calc(100% - 20px)' : '100%', margin: '0 auto', cursor: 'pointer', color: '#94a3b8', transition: 'color 0.2s' }} title={!isSidebarOpen ? `התנתקות (${user.name})` : ""} onMouseEnter={(e) => e.currentTarget.style.color = '#f87171'} onMouseLeave={(e) => e.currentTarget.style.color = '#94a3b8'}>
            <LogOut size={18} /> 
            {isSidebarOpen && <span style={{ marginRight: '10px', whiteSpace: 'nowrap' }}>התנתקות ({user.name})</span>}
          </div>
        </div>
      </aside>

      {/* --- תוכן מרכזי --- */}
      <main className={styles.mainContent}>
        
        <header className={styles.header}>
          <div style={{ display: 'flex', alignItems: 'center' }}>
            <button onClick={() => setSidebarOpen(true)} className={styles.mobileHamburger}><Menu size={24} /></button>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              {activeSpace && renderSpaceIcon(activeSpace.iconName, activeSpace.color, 24)}
              <h1 className={styles.spaceTitle} style={{ borderBottom: `3px solid ${activeSpace?.color || '#3b82f6'}`, margin: 0 }}>{activeSpace?.name || 'בחר מרחב'}</h1>
            </div>
          </div>
          
          <div style={{ position: 'relative' }}>
            <button onMouseEnter={() => setShowInfoTooltip(true)} onMouseLeave={() => setShowInfoTooltip(false)} className={styles.settingsBtn} style={{ cursor: 'help' }}>
              <Info size={20} />
            </button>
            {showInfoTooltip && (
              <div style={{ position: 'absolute', top: '100%', left: 0, marginTop: '10px', padding: '15px', background: '#1e293b', border: '1px solid #334155', borderRadius: '8px', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.5)', color: '#cbd5e1', fontSize: '0.85rem', width: 'max-content', zIndex: 100, textAlign: 'right' }}>
                <strong style={{ display: 'block', color: 'white', marginBottom: '8px', fontSize: '1.05rem' }}>אלדר ויז'ואל</strong>
                <div style={{ marginBottom: '4px' }}>גרסת מערכת: 2.19.4</div>
                <div style={{ color: '#94a3b8' }}>&copy; 2026 כל הזכויות שמורות.</div>
              </div>
            )}
          </div>
        </header>

        <div className={styles.content}>
          <div className={styles.searchBar}>
            <Search size={18} className={styles.searchIcon} />
            <input type="text" placeholder="חפש במסמכים, סרטונים ותוכן..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
          </div>

          {/* --- נושאים --- */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px', marginTop: '5px', padding: '0 5px' }}>
            <h3 style={{ fontSize: '0.9rem', color: '#94a3b8', margin: 0, fontWeight: 'normal' }}>נושאים</h3>
            <button onClick={() => setAddTabModalOpen(true)} className={styles.addCustomTabBtn} style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '0.85rem' }}>
              <Plus size={14}/> נושא חדש
            </button>
          </div>

          <div className={styles.customTabsWrapper} style={{ display: 'flex', alignItems: 'center', position: 'relative', marginBottom: '20px' }}>
            <div 
              ref={tabsScrollRef} 
              style={{ display: 'flex', flex: 1, overflowX: 'auto', gap: '10px', paddingBottom: '5px', scrollbarWidth: 'none', msOverflowStyle: 'none', scrollSnapType: 'x mandatory', WebkitMaskImage: 'linear-gradient(to right, transparent 0px, black 25px, black 100%)', maskImage: 'linear-gradient(to right, transparent 0px, black 25px, black 100%)' }} 
              className="hideScrollbar"
            >
              <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEndTabs}>
                <SortableContext items={currentSpaceTabs} strategy={horizontalListSortingStrategy}>
                  {currentSpaceTabs.map(tab => (
                    <SortableItem key={tab} id={tab} onClick={() => setActiveCustomTab(tab)} className={`${styles.customTab} ${activeCustomTab === tab ? styles.activeCustomTab : ''}`} style={{ flexShrink: 0, scrollSnapAlign: 'center' }}>
                      <span>{tab}</span>
                    </SortableItem>
                  ))}
                </SortableContext>
              </DndContext>
              <div style={{ flex: '0 0 25px', width: '25px', height: '1px' }}></div>
            </div>
            {currentSpaceTabs.length > 4 && (
              <button onClick={scrollTabsLeft} style={{ background: 'transparent', border: 'none', color: '#64748b', padding: '0 8px', cursor: 'pointer', animation: 'pulseLeft 1.5s infinite', zIndex: 2 }}>
                <ChevronLeft size={18} />
              </button>
            )}
          </div>

          {/* --- קטגוריות תוכן --- */}
          <div className={styles.categoryTabsWrapper} style={{ borderBottom: '1px solid #334155', marginBottom: '20px', display: 'flex', gap: '20px', overflowX: 'auto', paddingBottom: '5px' }}>
            <button onClick={() => setActiveCategoryTab('ראשי')} className={`${styles.categoryTab} ${activeCategoryTab === 'ראשי' ? styles.activeCategoryTab : ''}`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <LayoutGrid size={16} /> ראשי
            </button>
            <button onClick={() => setActiveCategoryTab('מועדפים')} className={`${styles.categoryTab} ${activeCategoryTab === 'מועדפים' ? styles.activeCategoryTab : ''}`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <Star size={16} /> מועדפים ({activeFavorites.length})
            </button>
            <button onClick={() => setActiveCategoryTab('מסמכים')} className={`${styles.categoryTab} ${activeCategoryTab === 'מסמכים' ? styles.activeCategoryTab : ''}`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <FileText size={16} /> מסמכים ({activeDocs.length})
            </button>
            <button onClick={() => setActiveCategoryTab('סרטונים')} className={`${styles.categoryTab} ${activeCategoryTab === 'סרטונים' ? styles.activeCategoryTab : ''}`} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <Play size={16} /> סרטונים ({activeVideos.length})
            </button>
          </div>

          {/* --- מועדפים (החלק שתוקן עם ה-img) --- */}
          {(activeCategoryTab === 'ראשי' || activeCategoryTab === 'מועדפים') && (
            <section className={styles.section} style={{ marginBottom: '30px' }}>
              <h2 className={styles.sectionTitle} style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' }}><Star size={20} color="#fbbf24" /> המועדפים</h2>
              <div className={styles.favoritesGrid}>
                <button className={styles.addGridBtn} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '5px' }}>
                  <Plus size={24} color="#64748b" />
                  <span className={styles.favTitle} style={{ color: '#94a3b8' }}>הוסף מועדף</span>
                </button>
                {activeFavorites.map(fav => (
                  <div key={fav._id} className={styles.favCard}>
                    <div className={styles.favIcon}>
                      {/* תיקון: חזרנו לתמונות אמיתיות במקום סתם טקסט */}
                      {fav.icon ? <img src={fav.icon} alt={fav.title} style={{ width: '100%', height: '100%', objectFit: 'contain' }} /> : <Star size={24} />}
                    </div>
                    <span className={styles.favTitle}>{fav.title}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* --- מסמכים --- */}
          {(activeCategoryTab === 'ראשי' || activeCategoryTab === 'מסמכים') && (
            <section className={styles.section} style={{ marginBottom: '30px' }}>
              <h2 className={styles.sectionTitle} style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' }}><FileText size={20} color="#3b82f6" /> מסמכים ({activeCustomTab})</h2>
              {activeDocs.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>אין מסמכים בנושא זה.</div>
              ) : (
                <div className={styles.visualsGrid} style={{ display: 'grid', gap: '10px' }}>
                   {activeDocs.map(doc => (
                     <div key={doc._id} className={styles.docRow} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px', background: '#1e293b', borderRadius: '8px' }}>
                       <span>{doc.title}</span>
                     </div>
                   ))}
                </div>
              )}
              <div style={{ textAlign: 'center', marginTop: '15px' }}>
                <button style={{ background: 'transparent', border: 'none', color: '#94a3b8', display: 'flex', alignItems: 'center', gap: '5px', margin: '0 auto', cursor: 'pointer' }}><Plus size={16} /> הוסף מסמך חדש</button>
              </div>
            </section>
          )}

          {/* --- סרטונים --- */}
          {(activeCategoryTab === 'ראשי' || activeCategoryTab === 'סרטונים') && (
            <section className={styles.section}>
              <h2 className={styles.sectionTitle} style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' }}><Play size={20} color="#a855f7" /> סרטונים ({activeCustomTab})</h2>
              <div className={styles.visualsGrid} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '15px' }}>
                {activeVideos.map(vid => (
                  <div key={vid._id} className={styles.squareCard} style={{ background: '#1e293b', borderRadius: '12px', overflow: 'hidden', position: 'relative' }}>
                    <div className={styles.videoThumbnail} style={{ position: 'relative', width: '100%', aspectRatio: '16/9' }}>
                      <img src={vid.thumbnail} alt={vid.title} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                      <button onClick={() => softDeleteVideo(vid._id)} style={{ position: 'absolute', bottom: '10px', left: '10px', background: 'rgba(0,0,0,0.6)', border: 'none', padding: '6px', borderRadius: '50%', color: '#f87171', cursor: 'pointer' }}>
                        <Trash2 size={16} />
                      </button>
                    </div>
                    <div className={styles.cardContent} style={{ padding: '12px' }}>
                      <h4 className={styles.cardTitle} style={{ margin: 0, fontSize: '0.95rem', color: '#f8fafc' }} dir="auto">{vid.title}</h4>
                    </div>
                  </div>
                ))}
              </div>
            </section>
          )}
        </div>
      </main>

      {/* --- חלונית סל מחזור --- */}
      {isRecycleBinOpen && (
        <div className={styles.modalOverlay} onClick={() => setIsRecycleBinOpen(false)} style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(15, 23, 42, 0.8)', backdropFilter: 'blur(4px)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div className={styles.modalContent} onClick={(e) => e.stopPropagation()} style={{ background: '#1e293b', padding: '25px', borderRadius: '16px', width: '90%', maxWidth: '500px', border: '1px solid #334155', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)' }}>
            
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', borderBottom: '1px solid #334155', paddingBottom: '15px' }}>
              <h2 className={styles.sectionTitle} style={{ margin: 0, display: 'flex', alignItems: 'center', gap: '8px', color: '#e2e8f0' }}>
                <Trash2 size={24} color="#38bdf8" /> סל מחזור
              </h2>
              <button onClick={() => setIsRecycleBinOpen(false)} style={{ background: 'transparent', border: 'none', color: '#94a3b8', cursor: 'pointer', display: 'flex' }}><X size={24} /></button>
            </div>

            <div style={{ maxHeight: '60vh', overflowY: 'auto', paddingRight: '5px' }}>
              {deletedVideos.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px 20px', color: '#64748b' }}>
                  <Trash2 size={56} style={{ opacity: 0.2, marginBottom: '15px' }} />
                  <h3 style={{ margin: '0 0 10px 0', color: '#cbd5e1', fontSize: '1.2rem' }}>הכל נקי כאן בינתיים</h3>
                  <p style={{ margin: 0, fontSize: '0.95rem', lineHeight: '1.5' }}>אין פריטים שנמחקו לאחרונה.</p>
                </div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                  {deletedVideos.map(vid => (
                    <div key={vid._id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px', background: 'rgba(255,255,255,0.03)', borderRadius: '8px', border: '1px solid #334155' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                         <div style={{ background: '#3b0764', padding: '8px', borderRadius: '6px', display: 'flex' }}><Play size={16} color="#a855f7" /></div>
                         <span style={{ fontSize: '0.95rem', color: '#e2e8f0' }}>{vid.title}</span>
                      </div>
                      <button onClick={() => restoreItem(vid._id, 'video')} style={{ background: 'rgba(16, 185, 129, 0.1)', border: '1px solid rgba(16, 185, 129, 0.2)', color: '#10b981', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', padding: '6px 12px', borderRadius: '6px', fontSize: '0.85rem', transition: 'all 0.2s' }}>
                        <RotateCcw size={14} /> שחזור
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div style={{ marginTop: '20px', display: 'flex', justifyContent: 'flex-end' }}>
               <button onClick={() => setIsRecycleBinOpen(false)} className={styles.cancelBtn} style={{ padding: '8px 20px', borderRadius: '8px', background: 'transparent', border: '1px solid #475569', color: '#cbd5e1', cursor: 'pointer' }}>סגור</button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}